"""Animated monochrome astronaut icon generated from tiikon.gif frames."""

WIDTH = 46
HEIGHT = 46
ROW_BYTES = 6
FRAME_COUNT = 16
FRAME_MS = 200
FRAMES = (
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
    bytes.fromhex(''),
)


def draw(disp, x, y, color=0xFFFF, frame=0):
    data = FRAMES[frame % FRAME_COUNT]
    for row in range(HEIGHT):
        base = row * ROW_BYTES
        yy = y + row
        for col in range(WIDTH):
            if data[base + (col >> 3)] & (0x80 >> (col & 7)):
                disp.pixel(x + col, yy, color)
